import React from 'react';
import Navbar from './Navbar';
import Footer from './Footer';
import Main from '../components/ApartmentMain';

const Layout = ({ children }) => {
    return (
        <div>
            <Main>
                <Navbar />
                <main>{children}</main>{' '}
                {/* Le contenu dynamique de chaque page */}
            </Main>
            <Footer />
        </div>
    );
};

export default Layout;
